    def _on_save(self):
        name = self.applicant_edit.text().strip()
        aid  = self.app_id_edit.text().strip()
        pos  = self.position_edit.text().strip()
        errs = []
        if not name: errs.append("Applicant Name required.")
        if not aid:  errs.append("Application ID required.")
        if not pos:  errs.append("Position required.")
        if errs:
            self.err_lbl.setText("⚠  " + "  •  ".join(errs))
            self.err_lbl.setVisible(True); return
        self.err_lbl.setVisible(False)
        self.interview_saved.emit({
            "applicant":    name,
            "app_id":       aid,
            "position":     pos,
            "datetime":     self.datetime_edit.dateTime().toString("dd MMM yyyy hh:mm AP"),
            "interviewers": self.interviewers_edit.text().strip(),
            "status":       self.status_combo.currentText(),
        })
        self.accept()


