    # ──────────────────────────────────────────────────────────────────────────
    # TABLE POPULATION
    # ──────────────────────────────────────────────────────────────────────────
    def _populate_table(self, data=None):
        rows = data if data is not None else self._interviews
        self.table.setRowCount(0)
        for i, iv in enumerate(rows):
            num,applicant,app_id,position,dt,interviewers,status = iv
            self.table.insertRow(i)
            self.table.setRowHeight(i,46)
            for col,txt in [(0,str(num)),(1,applicant),(2,app_id),(4,dt),(5,interviewers)]:
                it = QtWidgets.QTableWidgetItem(txt)
                it.setFlags(it.flags() & ~Qt.ItemFlag.ItemIsEditable)
                if col == 1:
                    it.setFont(QtGui.QFont("Segoe UI",11,QtGui.QFont.Weight.Bold))
                self.table.setItem(i,col,it)
            # Position
            pl = QtWidgets.QLabel(position); pl.setWordWrap(True)
            pl.setStyleSheet(f"color:{_TEXT_MID};font-size:11px;padding:4px 6px;")
            self.table.setCellWidget(i,3,pl)
            # Status badge
            fg,bg = STATUS_COLOURS.get(status,(_TEXT_MID,"#f3f4f6"))
            self.table.setCellWidget(i,6,self._centre(_Badge(status,fg,bg)))
            # Actions
            self.table.setCellWidget(i,7,self._action_widget(i))
        count = len(rows)
        self.showing_lbl.setText(
            f"Showing 1 to {min(10,count)} of {count} interviews")

    def _action_widget(self, row):
        w = QtWidgets.QWidget()
        hl = QtWidgets.QHBoxLayout(w)
        hl.setContentsMargins(4,0,4,0); hl.setSpacing(4)
        for ico,tip,col,slot in [
            ("👁","View",  "#64748b", lambda _,r=row: self._on_view(r)),
            ("✏","Edit",  "#2563eb", lambda _,r=row: self._on_edit(r)),
            ("🗑","Delete","#dc2626", lambda _,r=row: self._on_delete(r)),
        ]:
            b = QtWidgets.QPushButton(ico); b.setFixedSize(26,26)
            b.setToolTip(tip)
            b.setCursor(QtGui.QCursor(Qt.CursorShape.PointingHandCursor))
            b.setStyleSheet(f"""QPushButton{{background:{col}22;color:{col};
                border:1px solid {col}44;border-radius:5px;font-size:12px;}}
                QPushButton:hover{{background:{col}44;}}""")
            b.clicked.connect(slot); hl.addWidget(b)
        hl.addStretch()
        return w

    @staticmethod
    def _centre(widget):
        w = QtWidgets.QWidget()
        hl = QtWidgets.QHBoxLayout(w)
        hl.addWidget(widget)
        hl.setAlignment(Qt.AlignmentFlag.AlignLeft|Qt.AlignmentFlag.AlignVCenter)
        hl.setContentsMargins(6,0,0,0)
        return w

    @staticmethod
    def _stat_card(icon,icon_bg,label,value,sublabel):
        f = QtWidgets.QFrame()
        f.setFrameShape(QtWidgets.QFrame.Shape.NoFrame)
        f.setStyleSheet(f"QFrame{{background:{_WHITE};border:1px solid {_BORDER};border-radius:10px;}}")
        hl = QtWidgets.QHBoxLayout(f)
        hl.setContentsMargins(12,10,12,10); hl.setSpacing(10)
        il = QtWidgets.QLabel(icon); il.setFixedSize(38,38)
        il.setAlignment(Qt.AlignmentFlag.AlignCenter)
        il.setStyleSheet(f"background:{icon_bg};border-radius:19px;font-size:17px;")
        vl = QtWidgets.QVBoxLayout(); vl.setSpacing(1)
        for txt,sty in [(label,f"color:{_TEXT_GREY};font-size:10px;"),
                        (value,f"color:{_TEXT_DARK};font-size:22px;font-weight:bold;font-family:'Segoe UI',Arial;"),
                        (sublabel,f"color:{_TEXT_GREY};font-size:10px;")]:
            l = QtWidgets.QLabel(txt); l.setStyleSheet(sty); vl.addWidget(l)
        hl.addWidget(il); hl.addLayout(vl); hl.addStretch()
        return f

    @staticmethod
    def _section_lbl(text):
        l = QtWidgets.QLabel(text)
        l.setStyleSheet(f"color:{_TEXT_DARK};font-size:13px;font-weight:bold;"
                        "font-family:'Segoe UI',Arial;")
        return l

    # ──────────────────────────────────────────────────────────────────────────
    # SLOTS
    # ──────────────────────────────────────────────────────────────────────────
    def _on_tab(self, tab):
        self._active_tab = tab
        for name,btn in self._tab_btns.items():
            btn.setStyleSheet(_tab_style(name == tab))
        self._apply_filters()

    def _apply_filters(self):
        text = self.search_edit.text().lower()
        tab  = self._active_tab
        results = []
        for iv in self._interviews:
            num,applicant,app_id,position,dt,interviewers,status = iv
            if tab != "All Interviews" and status != tab: continue
            if text and not any(text in v.lower() for v in
                                (applicant,app_id,position,status)): continue
            results.append(iv)
        self._populate_table(results)

    def _on_schedule(self):
        dlg = ScheduleInterviewDialog(self)
        dlg.interview_saved.connect(self._append_interview)
        dlg.exec()

    def _append_interview(self, data):
        new_num = len(self._interviews) + 1
        self._interviews.insert(0,(
            new_num, data["applicant"], data["app_id"],
            data["position"], data["datetime"],
            data["interviewers"], data["status"]
        ))
        self._apply_filters()
        QtWidgets.QMessageBox.information(
            self,"Interview Scheduled",
            f"✅  Interview for '{data['applicant']}' has been scheduled.")

    def _on_view(self, row):
        if row >= len(self._interviews): return
        iv = self._interviews[row]
        QtWidgets.QMessageBox.information(
            self,"Interview Details",
            f"<b>{iv[1]}</b><br>ID: {iv[2]}<br>Position: {iv[3]}<br>"
            f"Date & Time: {iv[4]}<br>Interviewers: {iv[5]}<br>Status: {iv[6]}")

    def _on_edit(self, row):
        if row >= len(self._interviews): return
        iv = self._interviews[row]
        dlg = ScheduleInterviewDialog(self, data={
            "applicant":iv[1],"app_id":iv[2],"position":iv[3],
            "interviewers":iv[5],"status":iv[6]})
        dlg.interview_saved.connect(lambda d,r=row: self._save_edit(r,d))
        dlg.exec()

    def _save_edit(self, row, data):
        old = self._interviews[row]
        self._interviews[row] = (
            old[0], data["applicant"], data["app_id"],
            data["position"], data["datetime"],
            data["interviewers"], data["status"])
        self._apply_filters()

    def _on_delete(self, row):
        if row >= len(self._interviews): return
        name = self._interviews[row][1]
        reply = QtWidgets.QMessageBox.question(
            self,"Delete Interview",
            f"Delete interview for <b>{name}</b>? This cannot be undone.",
            QtWidgets.QMessageBox.StandardButton.Yes |
            QtWidgets.QMessageBox.StandardButton.No,
            QtWidgets.QMessageBox.StandardButton.No)
        if reply == QtWidgets.QMessageBox.StandardButton.Yes:
            self._interviews.pop(row)
            self._apply_filters()

    def _on_quick(self, label):
        QtWidgets.QMessageBox.information(
            self, label,
            f"'{label}' will be available in the next sprint.")
